{% if robokassa_graph_enabled %}
<script type="text/javascript">
(function() {
  function syncRobokassaCheckoutGraphs() {
    var graphContainers = document.querySelectorAll('.robokassa-checkout-graph');
    var activeMethods = [];

    for (var i = 0; i < graphContainers.length; i++) {
      var graphContainer = graphContainers[i];
      var radioWrapper = graphContainer.closest('.radio');
      var radioInput = radioWrapper ? radioWrapper.querySelector('input[name="payment_method"]') : null;
      var isActive = !!(radioInput && radioInput.checked);

      if (radioWrapper && radioWrapper.parentNode) {
        radioWrapper.parentNode.classList.add('robokassa-checkout-payment-list');
      }

      if (isActive) {
        graphContainer.classList.add('is-active');

        if (graphContainer.getAttribute('data-payment-method')) {
          activeMethods.push(graphContainer.getAttribute('data-payment-method'));
        }
      } else {
        graphContainer.classList.remove('is-active');
      }
    }

    if (typeof window.initRobokassaGraphs === 'function' && activeMethods.length) {
      window.initRobokassaGraphs(activeMethods.length === 1 ? activeMethods[0] : activeMethods);
    }
  }

  function bindRobokassaCheckoutGraphs() {
    var radios = document.querySelectorAll('input[name="payment_method"]');

    for (var i = 0; i < radios.length; i++) {
      if (radios[i].getAttribute('data-robokassa-graph-bound') === '1') {
        continue;
      }

      radios[i].setAttribute('data-robokassa-graph-bound', '1');
      radios[i].addEventListener('change', syncRobokassaCheckoutGraphs);
    }
  }

  function normalizeRobokassaCheckoutAgree() {
    var agrees = document.querySelectorAll('input[name="agree"]');

    for (var i = 0; i < agrees.length; i++) {
      var agree = agrees[i];
      var label = agree.closest ? agree.closest('label') : null;
      var holder = agree.closest ? agree.closest('.checkbox, .form-check') : null;
      var buttons = agree.closest ? agree.closest('.buttons') : null;
      var row = agree.closest ? agree.closest('.pull-right') : null;
      var scope = row || holder || agree.parentNode;

      if (label) {
        label.classList.add('robokassa-checkout-agree');
      }

      if (holder) {
        holder.classList.add('robokassa-checkout-agree-holder');
      }

      if (buttons) {
        buttons.classList.add('robokassa-checkout-buttons');
      }

      if (row) {
        row.classList.add('robokassa-checkout-buttons-row');
      }

      if (!label && scope && scope.getAttribute('data-robokassa-agree-normalized') !== '1') {
        scope.setAttribute('data-robokassa-agree-normalized', '1');

        var line = document.createElement('label');
        var text = document.createElement('span');
        var button = scope.querySelector('#button-payment-method, input[type="button"], button, input[type="submit"]');
        var nodes = Array.prototype.slice.call(scope.childNodes);

        line.className = 'robokassa-checkout-agree';
        text.className = 'robokassa-checkout-agree-text';

        scope.insertBefore(line, button && button.parentNode === scope ? button : scope.firstChild);
        line.appendChild(agree);
        line.appendChild(text);

        for (var j = 0; j < nodes.length; j++) {
          var node = nodes[j];

          if (node === line || node === agree || node === button) {
            continue;
          }

          if (node.nodeType === 1) {
            var tagName = node.tagName ? node.tagName.toLowerCase() : '';

            if (tagName === 'script' || tagName === 'style') {
              continue;
            }

            if (button && node.contains && node.contains(button)) {
              continue;
            }
          }

          text.appendChild(node);
        }
      }
    }
  }

  normalizeRobokassaCheckoutAgree();

  function initRobokassaCheckoutGraphs() {
    bindRobokassaCheckoutGraphs();
    normalizeRobokassaCheckoutAgree();
    syncRobokassaCheckoutGraphs();
  }

  if (window.__robokassaCheckoutGraphsLoading) {
    var waitInterval = window.setInterval(function() {
      if (typeof window.initRobokassaGraphs === 'function') {
        window.clearInterval(waitInterval);
        initRobokassaCheckoutGraphs();
      }
    }, 100);

    window.setTimeout(function() {
      window.clearInterval(waitInterval);
    }, 5000);

    return;
  }

  if (typeof window.initRobokassaGraphs === 'function') {
    initRobokassaCheckoutGraphs();
    return;
  }

  window.__robokassaCheckoutGraphsLoading = true;

  var script = document.createElement('script');
  script.src = '{{ robokassa_graph_script }}';
  script.onload = function() {
    window.__robokassaCheckoutGraphsLoading = false;
    initRobokassaCheckoutGraphs();
  };
  script.onerror = function() {
    window.__robokassaCheckoutGraphsLoading = false;
  };

  document.head.appendChild(script);
})();
</script>
